SELECT /* @SQLID=SUB020503-01#Sql001 */ * FROM ( SELECT
/*+ FULL(A@SEL$5) OPT_PARAM('_optimizer_skip_scan_enabled', 'false') */
count(*) over() AS TOTAL_COUNT, BROKER_CODE AS BROKER_CODE, BROKER_NAME AS BROKER_NAME, BROKER_CHARGE_CODE AS EMP_CODE, BROKER_CHARGE_NAME AS BROKER_CHARGE_NAME, BUTEN_CODE AS BUTEN, ACCOUNT_NUMBER AS ACCOUNT_NUMBER, DEALER_NUMBER AS DEALER_NUMBER, CUSTOMER_ATTRIBUTE_NAME AS COURSE, NAME_KANJI AS CUSTOMER_NAME_KANJI, NAME_KANA AS CUSTOMER_NAME_KANA, PRODUT_NAME AS SECURITY_CLASS, BASE_DATE AS HOLDINGC_DATE, BRAND_CODE AS BRAND_CODE, BRAND_NAME AS BRAND_NAME, QUANTITY AS QUANTITY, ACQUIRE_PRICE AS REFERENCE_PRICE, PRICE AS PRICE, SUM(NVL(FUND_BALANCE,0)) AS VALUATION, TRUST_FEE_RATE AS TRUST_FEE_RATE, CURRENCY AS CURRENCY, EXCHANGE_RATE AS FX_RATE, SUM(NVL(YEN_TRUST_FEE,0)) AS TRUST_FEE_AMOUNT, BROKER_BRANCH_CODE AS BRANCH_CODE, BROKER_BRANCH_NAME AS BRANCH_NAME FROM ( SELECT TFR.BROKER_CODE AS BROKER_CODE, TFR.BROKER_NAME AS BROKER_NAME, TFR.BROKER_CHARGE_CODE AS BROKER_CHARGE_CODE, TFR.BROKER_CHARGE_NAME AS BROKER_CHARGE_NAME, TFR.BUTEN_CODE AS BUTEN_CODE, TFR.ACCOUNT_NUMBER AS ACCOUNT_NUMBER, TFR.DEALER_NUMBER AS DEALER_NUMBER, TFR.CUSTOMER_ATTRIBUTE_NAME AS CUSTOMER_ATTRIBUTE_NAME, TFR.NAME_KANJI AS NAME_KANJI, TFR.NAME_KANA AS NAME_KANA, TFR.PRODUT_NAME AS PRODUT_NAME, TO_CHAR(TO_DATE(TFR.BASE_DATE,'YYYY/MM/DD'),'YYYY/MM/DD') AS BASE_DATE, TFR.BRAND_CODE AS BRAND_CODE, TFR.BRAND_NAME AS BRAND_NAME, NVL(TFR.QUANTITY,0) AS QUANTITY, NVL(TFR.ACQUIRE_PRICE,0) AS ACQUIRE_PRICE, NVL(TFR.PRICE,0) AS PRICE, NVL(TFR.FUND_BALANCE,0) AS FUND_BALANCE, NVL(TFR.TRUST_FEE_RATE,0) AS TRUST_FEE_RATE, TFR.CURRENCY AS CURRENCY, NVL(TFR.EXCHANGE_RATE,0) AS EXCHANGE_RATE, NVL(TFR.YEN_TRUST_FEE,0) AS YEN_TRUST_FEE, TFR.BROKER_BRANCH_CODE AS BROKER_BRANCH_CODE, TFR.BROKER_BRANCH_NAME AS BROKER_BRANCH_NAME FROM ( SELECT TFR.*, MUAI.NAME_KANA, MB.BRANCH_NAME AS BROKER_BRANCH_NAME FROM V_TRUST_FEE_DAY TFR LEFT OUTER JOIN MEDIATE_USER_ATTRIBUTE_INFO MUAI ON TFR.BROKER_CODE = MUAI.BROKER_CODE AND TFR.BUTEN_CODE = MUAI.BUTEN_CODE AND TFR.ACCOUNT_NUMBER = MUAI.ACCOUNT_NUMBER LEFT OUTER JOIN MEDIATE_BRANCH MB ON TFR.BROKER_CODE = MB.BROKER_CODE AND TFR.BROKER_BRANCH_CODE = MB.BROKER_BRANCH_CODE ) TFR
) GROUP BY BROKER_CODE, BROKER_NAME, BROKER_CHARGE_CODE, BROKER_CHARGE_NAME, BUTEN_CODE, ACCOUNT_NUMBER, DEALER_NUMBER, CUSTOMER_ATTRIBUTE_NAME, NAME_KANJI, NAME_KANA, PRODUT_NAME, BASE_DATE, BRAND_CODE, BRAND_NAME, QUANTITY, ACQUIRE_PRICE, PRICE, TRUST_FEE_RATE, CURRENCY, EXCHANGE_RATE, BROKER_BRANCH_CODE, BROKER_BRANCH_NAME ORDER BY BASE_DATE DESC, BROKER_CODE ASC, BUTEN_CODE ASC, ACCOUNT_NUMBER ASC ) WHERE ROWNUM <= #{req.maxRowNum}

SELECT /* @SQLID=SUB020503-01#Sql002 */ * FROM ( SELECT
/*+ FULL(A@SEL$5) OPT_PARAM('_optimizer_skip_scan_enabled', 'false') */
count(*) over() AS TOTAL_COUNT, BROKER_CODE AS BROKER_CODE, BROKER_NAME AS BROKER_NAME, BROKER_CHARGE_CODE AS EMP_CODE, BROKER_CHARGE_NAME AS BROKER_CHARGE_NAME, BUTEN_CODE AS BUTEN, ACCOUNT_NUMBER AS ACCOUNT_NUMBER, DEALER_NUMBER AS DEALER_NUMBER, CUSTOMER_ATTRIBUTE_NAME AS COURSE, NAME_KANJI AS CUSTOMER_NAME_KANJI, NAME_KANA AS CUSTOMER_NAME_KANA, PRODUT_NAME AS SECURITY_CLASS, BASE_DATE AS HOLDINGC_DATE, SUM(NVL(FUND_BALANCE,0)) AS VALUATION, CURRENCY AS CURRENCY, EXCHANGE_RATE AS FX_RATE, SUM(NVL(YEN_TRUST_FEE,0)) AS TRUST_FEE_AMOUNT, BROKER_BRANCH_CODE AS BRANCH_CODE, BROKER_BRANCH_NAME AS BRANCH_NAME FROM ( SELECT TFR.BROKER_CODE AS BROKER_CODE, TFR.BROKER_NAME AS BROKER_NAME, TFR.BROKER_CHARGE_CODE AS BROKER_CHARGE_CODE, TFR.BROKER_CHARGE_NAME AS BROKER_CHARGE_NAME, TFR.BUTEN_CODE AS BUTEN_CODE, TFR.ACCOUNT_NUMBER AS ACCOUNT_NUMBER, TFR.DEALER_NUMBER AS DEALER_NUMBER, TFR.CUSTOMER_ATTRIBUTE_NAME AS CUSTOMER_ATTRIBUTE_NAME, TFR.NAME_KANJI AS NAME_KANJI, TFR.NAME_KANA AS NAME_KANA, TFR.PRODUT_NAME AS PRODUT_NAME, TO_CHAR(TO_DATE(TFR.BASE_DATE,'YYYY/MM/DD'),'YYYY/MM/DD') AS BASE_DATE, NVL(TFR.FUND_BALANCE,0) AS FUND_BALANCE, TFR.CURRENCY AS CURRENCY, NVL(TFR.EXCHANGE_RATE,0) AS EXCHANGE_RATE, NVL(TFR.YEN_TRUST_FEE,0) AS YEN_TRUST_FEE, TFR.BROKER_BRANCH_CODE AS BROKER_BRANCH_CODE, TFR.BROKER_BRANCH_NAME AS BROKER_BRANCH_NAME FROM ( SELECT TFR.*, MUAI.NAME_KANA, MB.BRANCH_NAME AS BROKER_BRANCH_NAME FROM V_TRUST_FEE_DAY TFR LEFT OUTER JOIN MEDIATE_USER_ATTRIBUTE_INFO MUAI ON TFR.BROKER_CODE = MUAI.BROKER_CODE AND TFR.BUTEN_CODE = MUAI.BUTEN_CODE AND TFR.ACCOUNT_NUMBER = MUAI.ACCOUNT_NUMBER LEFT OUTER JOIN MEDIATE_BRANCH MB ON TFR.BROKER_CODE = MB.BROKER_CODE AND TFR.BROKER_BRANCH_CODE = MB.BROKER_BRANCH_CODE ) TFR
) GROUP BY BROKER_CODE, BROKER_NAME, BROKER_CHARGE_CODE, BROKER_CHARGE_NAME, BUTEN_CODE, ACCOUNT_NUMBER, DEALER_NUMBER, CUSTOMER_ATTRIBUTE_NAME, NAME_KANJI, NAME_KANA, PRODUT_NAME, BASE_DATE, CURRENCY, EXCHANGE_RATE, BROKER_BRANCH_CODE, BROKER_BRANCH_NAME ORDER BY BASE_DATE DESC, BROKER_CODE ASC, BUTEN_CODE ASC, ACCOUNT_NUMBER ASC ) WHERE ROWNUM <= #{req.maxRowNum}

SELECT /* @SQLID=SUB020503-01#Sql003 */ * FROM ( SELECT
/*+ FULL(A@SEL$5) OPT_PARAM('_optimizer_skip_scan_enabled', 'false') */
count(*) over() AS TOTAL_COUNT, BROKER_CODE AS BROKER_CODE, BROKER_NAME AS BROKER_NAME, PRODUT_NAME AS SECURITY_CLASS, BASE_DATE AS HOLDINGC_DATE, SUM(NVL(FUND_BALANCE,0)) AS VALUATION, CURRENCY AS CURRENCY, EXCHANGE_RATE AS FX_RATE, SUM(NVL(YEN_TRUST_FEE,0)) AS TRUST_FEE_AMOUNT FROM ( SELECT TFR.BROKER_CODE AS BROKER_CODE, TFR.BROKER_NAME AS BROKER_NAME, TFR.PRODUT_NAME AS PRODUT_NAME, TO_CHAR(TO_DATE(TFR.BASE_DATE,'YYYY/MM/DD'),'YYYY/MM/DD') AS BASE_DATE, NVL(TFR.FUND_BALANCE,0) AS FUND_BALANCE, TFR.CURRENCY AS CURRENCY, NVL(TFR.EXCHANGE_RATE,0) AS EXCHANGE_RATE, NVL(TFR.YEN_TRUST_FEE,0) AS YEN_TRUST_FEE FROM ( SELECT TFR.*, MUAI.NAME_KANA FROM V_TRUST_FEE_DAY TFR LEFT OUTER JOIN MEDIATE_USER_ATTRIBUTE_INFO MUAI ON TFR.BROKER_CODE = MUAI.BROKER_CODE AND TFR.BUTEN_CODE = MUAI.BUTEN_CODE AND TFR.ACCOUNT_NUMBER = MUAI.ACCOUNT_NUMBER ) TFR
) GROUP BY BROKER_CODE, BROKER_NAME, PRODUT_NAME, BASE_DATE, CURRENCY, EXCHANGE_RATE ORDER BY BASE_DATE DESC, BROKER_CODE ASC ) WHERE ROWNUM <= #{req.maxRowNum}

SELECT /* @SQLID=SUB020503-01#Sql004 */ * FROM ( SELECT
/*+ FULL(TFR@SEL$4) OPT_PARAM('_optimizer_skip_scan_enabled', 'false') */
count(*) over() AS TOTAL_COUNT, BROKER_CODE AS BROKER_CODE, BROKER_NAME AS BROKER_NAME, BROKER_CHARGE_CODE AS EMP_CODE, BROKER_CHARGE_NAME AS BROKER_CHARGE_NAME, BUTEN_CODE AS BUTEN, ACCOUNT_NUMBER AS ACCOUNT_NUMBER, DEALER_NUMBER AS DEALER_NUMBER, CUSTOMER_ATTRIBUTE_NAME AS COURSE, NAME_KANJI AS CUSTOMER_NAME_KANJI, NAME_KANA AS CUSTOMER_NAME_KANA, PRODUT_NAME AS SECURITY_CLASS, BASE_MONTH AS BASE_MONTH, BRAND_CODE AS BRAND_CODE, BRAND_NAME AS BRAND_NAME, SUM(NVL(FUND_BALANCE,0)) AS VALUATION, CURRENCY AS CURRENCY, EXCHANGE_RATE AS FX_RATE, SUM(NVL(YEN_TRUST_FEE,0)) AS TRUST_FEE_AMOUNT, BROKER_BRANCH_CODE AS BRANCH_CODE, BROKER_BRANCH_NAME AS BRANCH_NAME FROM ( SELECT TFR.BROKER_CODE AS BROKER_CODE, TFR.BROKER_NAME AS BROKER_NAME, TFR.BROKER_CHARGE_CODE AS BROKER_CHARGE_CODE, TFR.BROKER_CHARGE_NAME AS BROKER_CHARGE_NAME, TFR.BUTEN_CODE AS BUTEN_CODE, TFR.ACCOUNT_NUMBER AS ACCOUNT_NUMBER, TFR.DEALER_NUMBER AS DEALER_NUMBER, TFR.CUSTOMER_ATTRIBUTE_NAME AS CUSTOMER_ATTRIBUTE_NAME, TFR.NAME_KANJI AS NAME_KANJI, TFR.NAME_KANA AS NAME_KANA, TFR.PRODUT_NAME AS PRODUT_NAME, TO_CHAR(TO_DATE(TFR.BASE_DATE,'YYYY/MM'),'YYYY/MM') AS BASE_MONTH, TFR.BRAND_CODE AS BRAND_CODE, TFR.BRAND_NAME AS BRAND_NAME, NVL(TFR.FUND_BALANCE,0) AS FUND_BALANCE, TFR.CURRENCY AS CURRENCY, NVL(TFR.EXCHANGE_RATE,0) AS EXCHANGE_RATE, NVL(TFR.YEN_TRUST_FEE,0) AS YEN_TRUST_FEE, TFR.BROKER_BRANCH_CODE AS BROKER_BRANCH_CODE, TFR.BROKER_BRANCH_NAME AS BROKER_BRANCH_NAME FROM ( SELECT TFR.*, MUAI.NAME_KANA, MB.BRANCH_NAME AS BROKER_BRANCH_NAME FROM V_TRUST_FEE_MONTH TFR LEFT OUTER JOIN MEDIATE_USER_ATTRIBUTE_INFO MUAI ON TFR.BROKER_CODE = MUAI.BROKER_CODE AND TFR.BUTEN_CODE = MUAI.BUTEN_CODE AND TFR.ACCOUNT_NUMBER = MUAI.ACCOUNT_NUMBER LEFT OUTER JOIN MEDIATE_BRANCH MB ON TFR.BROKER_CODE = MB.BROKER_CODE AND TFR.BROKER_BRANCH_CODE = MB.BROKER_BRANCH_CODE ) TFR
) GROUP BY BROKER_CODE, BROKER_NAME, BROKER_CHARGE_CODE, BROKER_CHARGE_NAME, BUTEN_CODE, ACCOUNT_NUMBER, DEALER_NUMBER, CUSTOMER_ATTRIBUTE_NAME, NAME_KANJI, NAME_KANA, PRODUT_NAME, BASE_MONTH, BRAND_CODE, BRAND_NAME, CURRENCY, EXCHANGE_RATE, BROKER_BRANCH_CODE, BROKER_BRANCH_NAME ORDER BY BASE_MONTH DESC, BROKER_CODE ASC, BUTEN_CODE ASC, ACCOUNT_NUMBER ASC ) WHERE ROWNUM <= #{req.maxRowNum}

