SELECT /* @SQLID=SUB020503-01#Sql006 */ * FROM ( SELECT
/*+ FULL(TFR@SEL$4) OPT_PARAM('_optimizer_skip_scan_enabled', 'false') */
count(*) over() AS TOTAL_COUNT, BROKER_CODE AS BROKER_CODE, BROKER_NAME AS BROKER_NAME, PRODUT_NAME AS SECURITY_CLASS, BASE_MONTH AS BASE_MONTH, SUM(NVL(FUND_BALANCE,0)) AS VALUATION, CURRENCY AS CURRENCY, EXCHANGE_RATE AS FX_RATE, SUM(NVL(YEN_TRUST_FEE,0)) AS TRUST_FEE_AMOUNT FROM ( SELECT TFR.BROKER_CODE AS BROKER_CODE, TFR.BROKER_NAME AS BROKER_NAME, TFR.PRODUT_NAME AS PRODUT_NAME, TO_CHAR(TO_DATE(TFR.BASE_DATE,'YYYY/MM'),'YYYY/MM') AS BASE_MONTH, NVL(TFR.FUND_BALANCE,0) AS FUND_BALANCE, TFR.CURRENCY AS CURRENCY, NVL(TFR.EXCHANGE_RATE,0) AS EXCHANGE_RATE, NVL(TFR.YEN_TRUST_FEE,0) AS YEN_TRUST_FEE FROM ( SELECT TFR.*, MUAI.NAME_KANA FROM V_TRUST_FEE_MONTH TFR LEFT OUTER JOIN MEDIATE_USER_ATTRIBUTE_INFO MUAI ON TFR.BROKER_CODE = MUAI.BROKER_CODE AND TFR.BUTEN_CODE = MUAI.BUTEN_CODE AND TFR.ACCOUNT_NUMBER = MUAI.ACCOUNT_NUMBER ) TFR
