mapper.sql:
WHERE
    TFR.PRODUT_CD IN

        #{securityClass}


    AND TFR.PRODUT_CD != '30'



        AND TFR.BASE_DATE >= TO_CHAR(TO_DATE(#{req.periodFrom}, 'YYYY/MM/DD'), 'YYYYMMDD')
        AND TFR.BASE_DATE <= TO_CHAR(TO_DATE(#{req.periodTo}, 'YYYY/MM/DD'), 'YYYYMMDD')




        AND TFR.BASE_DATE >= TO_CHAR(TO_DATE(#{req.periodFrom}, 'YYYY/MM'), 'YYYYMM')
        AND TFR.BASE_DATE <= TO_CHAR(TO_DATE(#{req.periodTo}, 'YYYY/MM'), 'YYYYMM')




        AND TFR.BUTEN_CODE =#{req.butenCode}




        AND TFR.ACCOUNT_NUMBER = TO_NUMBER(#{req.accountNumber})




         AND (TFR.BRAND_CODE = #{req.brandCode} 
             OR TFR.BRAND_CODE = '0' || #{req.brandCode} )






            AND TFR.BROKER_BRANCH_CODE =#{req.branchCode}





        AND BROKER_CODE IN

            #{brokerCode}





         AND TFR.BROKER_CODE NOT IN

             #{brokerCode}





        AND TFR.BROKER_CHARGE_CODE =#{req.empCode}




         AND (TFR.NAME_KANJI = #{req.customerNameKanjiKana}
             OR TFR.NAME_KANA = #{req.customerNameKanjiKana} )




         AND (TFR.NAME_KANJI LIKE #{req.customerNameKanjiKana} || '%'
             OR TFR.NAME_KANA LIKE #{req.customerNameKanjiKana} || '%' )




         AND (TFR.NAME_KANJI LIKE '%' || #{req.customerNameKanjiKana} || '%'
             OR TFR.NAME_KANA LIKE '%' || #{req.customerNameKanjiKana} || '%' )


    AND TFR.CUSTOMER_ATTRIBUTE IN

        #{course}



        AND (TFR.BROKER_CODE IN


                ) OR TFR.BROKER_CODE IN (


                ,

            #{brokerCharge.brokerCode}

        )


        AND ((TFR.BROKER_CODE, TFR.BROKER_CHARGE_CODE) IN


                ) OR (TFR.BROKER_CODE, TFR.BROKER_CHARGE_CODE) IN (


                ,

            (#{brokerCharge.brokerCode}, #{brokerCharge.empCode})

        )
